// Construir un mensaje por cada admin con la información del error
// Datos del error desde el Error Trigger
// En ejecución real (como error workflow), los datos del error están en el nodo "Error Trigger".
// En ejecuciones manuales, puede no existir, así que usamos un fallback seguro.

let errorData;

try {
  // n8n 1.x: acceder al nodo de origen de error
  errorData = $item(0).$node["Error Trigger"]?.json;
} catch (e) {
  errorData = undefined;
}

if (!errorData || Object.keys(errorData).length === 0) {
  // Fallback: usar el propio $json (útil para pruebas manuales)
  errorData = $json || {};
}

// Usar accesos defensivos para evitar errores si alguna propiedad no existe
const workflowName = errorData.workflow?.name || errorData.workflowName || errorData.workflow_id || 'Workflow desconocido';
const workflowId = errorData.workflow?.id || errorData.workflowId || errorData.workflow_id || 'N/A';
const errorMessage = errorData.error?.message || errorData.message || errorData.error || 'Error sin mensaje';
const timestamp = errorData.timestamp || new Date().toISOString();
const executionId = errorData.execution?.id || errorData.executionId || errorData.execution_id || 'N/A';

console.log('⚠️ Notificador de errores - Datos del error:');
console.log({ workflowName, workflowId, errorMessage, timestamp, executionId, rawError: errorData });

// Por cada admin (items actuales), generamos un nuevo item con los datos del mensaje
return items.map(item => {
  const admin = item.json;
  return {
    json: {
      chat_id: admin.chat_id,
      user_id: admin.user_id,
      user_name: admin.user_name,
      workflow_name: workflowName,
      workflow_id: workflowId,
      error_message: errorMessage,
      timestamp,
      execution_id: executionId
    }
  };
});

